import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { WantedListParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/WantedListParser';

export class WantedListEvent extends MessageEvent implements IMessageEvent {
    constructor(callback: Function) {
        super(callback, WantedListParser);
       // console.log('[🚨] WantedListEvent initialized!');
    }

    public getParser(): WantedListParser {
        return this.parser as WantedListParser;
    }
}
